import React, { useState } from 'react';
import { Outlet, NavLink, useNavigate } from 'react-router-dom';
import { Activity, LayoutDashboard, Settings, PanelLeft, PanelLeftClose, LogOut, Users, Receipt, User, Clock, UserCheck, Layers } from 'lucide-react';
import { useAuthStore } from '../store/useAuthStore';
import { CommandPalette } from '../../features/dashboard/components/CommandPalette';

export const DashboardLayout = () => {
  const { user, logout } = useAuthStore();
  const navigate = useNavigate();
  const [isCollapsed, setIsCollapsed] = useState(true);

  // We will build the full Command Palette logic in the next phase!
  // For now, it will be visually integrated into the sidebar.

  const handleLogout = () => {
    logout();
    navigate('/login');
  };

  const menuItems = [
    { name: 'Dashboard', icon: LayoutDashboard, path: '/' },
    { name: 'Activity', icon: Clock, path: '/activity', badge: '3' },
    { name: 'Friends', icon: UserCheck, path: '/friends' },
    { name: 'Groups', icon: Layers, path: '/groups' },
    { name: 'Expenses', icon: Receipt, path: '/expenses' },
    { name: 'Profile', icon: User, path: '/profile' },
  ];

  return (
    <div className="flex h-screen w-screen bg-[#050505] text-white font-sans overflow-hidden">

      {/* Sidebar - Precision Transition */}
      <aside 
        className={`${isCollapsed ? 'w-20' : 'w-64'} border-r border-white/10 bg-[#0c0c0e] flex flex-col justify-between hidden md:flex shadow-2xl relative transition-all duration-500 cubic-bezier(0.4, 0, 0.2, 1) z-20`}
      >

        {/* Top Branding & Navigation */}
        <div className="flex flex-col h-full">
          {/* Header Block */}
          <div className={`p-5 flex items-center h-20 ${isCollapsed ? 'justify-center' : 'justify-between'} transition-all duration-300`}>

            {/* Branding */}
            <div className={`flex items-center gap-3 overflow-hidden ${isCollapsed ? 'w-0 opacity-0 absolute' : 'w-auto opacity-100 relative'} transition-all duration-500`}>
              <div className="h-10 w-10 shrink-0 bg-white/10 border border-white/20 rounded-xl flex items-center justify-center backdrop-blur-md shadow-inner">
                <Activity className="h-5 w-5 text-white" strokeWidth={2.5} />
              </div>
              <h1 className="font-display text-xl font-bold tracking-tight text-white whitespace-nowrap">
                SplitLedger
              </h1>
            </div>

            {/* Manual Inline Toggle */}
            <button 
              onClick={() => setIsCollapsed(!isCollapsed)}
              className="p-2 rounded-lg text-zinc-500 hover:text-white hover:bg-white/5 transition-all group relative"
              title="Toggle Sidebar"
            >
              {isCollapsed ? <PanelLeft className="h-5 w-5" /> : <PanelLeftClose className="h-5 w-5" />}
            </button>
          </div>

          {/* Navigation Links */}
          <nav className="space-y-1.5 px-3 mt-2 flex-1">
            {menuItems.map((item) => (
              <NavLink
                key={item.name}
                to={item.path}
                className={({ isActive }) =>
                  `flex items-center ${isCollapsed ? 'justify-center' : 'justify-start gap-4 px-3'} py-3 rounded-lg font-medium transition-all duration-200 group relative ` +
                  (isActive 
                    ? `text-white bg-white/10 shadow-sm border border-white/10` 
                    : `text-zinc-500 hover:text-zinc-200 hover:bg-white/5 border border-transparent`)
                }
                title={isCollapsed ? item.name : undefined}
              >
                {({ isActive }) => {
                  const Icon = item.icon;
                  return (
                    <>
                      <div className="relative flex items-center justify-center">
                        <Icon className={`h-[20px] w-[20px] shrink-0 ${isActive ? 'text-cyan-400' : 'text-zinc-500 group-hover:text-zinc-300'} transition-colors`} />
                        {isCollapsed && item.badge && (
                          <span className="absolute -top-1.5 -right-2 bg-cyan-500 text-black text-[9px] font-bold w-3.5 h-3.5 rounded-full flex items-center justify-center border border-[#0c0c0e] shadow-[0_0_8px_rgba(34,211,238,0.4)]">
                            {item.badge}
                          </span>
                        )}
                      </div>

                      {!isCollapsed && (
                        <div className="flex items-center justify-between w-full overflow-hidden transition-all duration-300">
                          <span className="text-[14px] whitespace-nowrap">{item.name}</span>
                          {/* Optional Notification Badge */}
                          {item.badge && (
                            <span className="ml-auto bg-cyan-500/20 text-cyan-400 border border-cyan-500/30 text-[10px] font-bold px-2 py-0.5 rounded-full shadow-[0_0_8px_rgba(34,211,238,0.2)]">
                              {item.badge}
                            </span>
                          )}
                        </div>
                      )}

                      {/* Glowing Accent Indicator */}
                      {isActive && (
                        <div className="absolute left-0 w-1 h-6 bg-gradient-to-b from-cyan-400 to-blue-600 rounded-r-md shadow-[0_0_8px_rgba(34,211,238,0.6)]"></div>
                      )}
                    </>
                  );
                }}
              </NavLink>
            ))}
          </nav>
        </div>

        {/* Bottom Menu Items -> Separated out like Settings */}
        <div className="px-3 pb-4">
           <NavLink
              to="/settings"
              className={({ isActive }) =>
                `flex items-center ${isCollapsed ? 'justify-center' : 'justify-start gap-4 px-3'} py-3 rounded-lg font-medium transition-all duration-200 group relative ` +
                (isActive 
                  ? `text-white bg-white/10 shadow-sm border border-white/10` 
                  : `text-zinc-500 hover:text-zinc-200 hover:bg-white/5 border border-transparent`)
              }
              title={isCollapsed ? 'Settings' : undefined}
            >
              {({ isActive }) => (
                  <>
                    <Settings className={`h-[20px] w-[20px] shrink-0 ${isActive ? 'text-cyan-400' : 'text-zinc-500 group-hover:text-zinc-300'}`} />
                    {!isCollapsed && <span className="text-[14px] whitespace-nowrap">Settings</span>}
                    {isActive && (
                      <div className="absolute left-0 w-1 h-6 bg-gradient-to-b from-cyan-400 to-blue-600 rounded-r-md shadow-[0_0_8px_rgba(34,211,238,0.6)]"></div>
                    )}
                  </>
                )}
            </NavLink>
        </div>

        {/* Persistent User Profile & Logout section */}
        <div className={`p-4 border-t border-white/10 bg-[#0a0a0c] flex items-center ${isCollapsed ? 'justify-center flex-col gap-4' : 'justify-between'}`}>
          {!isCollapsed && (
            <div className="flex flex-col whitespace-nowrap overflow-hidden pr-2">
              <span className="text-[13px] font-bold text-white leading-tight truncate">
                {user?.displayName || 'Unknown User'}
              </span>
              <span className="text-[11px] font-medium text-zinc-500 truncate max-w-[140px]">
                {user?.email || 'No Email'}
              </span>
            </div>
          )}

          <button 
            onClick={handleLogout}
            className="p-2 rounded-lg text-zinc-500 hover:text-rose-400 hover:bg-rose-500/10 transition-colors"
            title="Sign Out"
          >
            <LogOut className="h-5 w-5" strokeWidth={2.5} />
          </button>
        </div>
      </aside>

      {/* Global Modals */}
      <CommandPalette />

      {/* Main Content Area */}
      <main className="flex-1 relative overflow-hidden flex flex-col">
        <div className="absolute top-0 right-0 w-[600px] h-[600px] bg-cyan-500/5 rounded-full blur-[150px] pointer-events-none"></div>
        <div className="flex-1 overflow-y-auto w-full h-full relative z-10">
            <Outlet />
        </div>
      </main>
    </div>
  );
};

import React, { useState, useRef, useEffect } from 'react';
import { useNavigate, useLocation } from 'react-router-dom';
import { ArrowRight, LockKeyhole, ShieldCheck, Eye, EyeOff } from 'lucide-react';
import { apiClient } from '../../../shared/api/axios';

type Step = 'otp' | 'password';

export const ResetPassword = () => {
  const navigate = useNavigate();
  const location = useLocation();
  const identifier = new URLSearchParams(location.search).get('identifier');

  const [step, setStep] = useState<Step>('otp');
  const [otp, setOtp] = useState<string[]>(['', '', '', '', '', '']);
  const [identifierInput, setIdentifierInput] = useState(identifier || '');
  const [password, setPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');
  const [showPassword, setShowPassword] = useState(false);
  const [showConfirm, setShowConfirm] = useState(false);
  const [error, setError] = useState('');
  const [success, setSuccess] = useState(false);
  const [loading, setLoading] = useState(false);
  const [resendLoading, setResendLoading] = useState(false);
  const [resendMessage, setResendMessage] = useState('');
  const [resendCooldown, setResendCooldown] = useState(0);

  const inputRefs = useRef<(HTMLInputElement | null)[]>([]);

  useEffect(() => {
    let timer: ReturnType<typeof setTimeout>;
    if (resendCooldown > 0) {
      timer = setTimeout(() => setResendCooldown(resendCooldown - 1), 1000);
    }
    return () => clearTimeout(timer);
  }, [resendCooldown]);

  useEffect(() => {
    if (!identifier) navigate('/login');
  }, [identifier, navigate]);

  useEffect(() => {
    if (step === 'otp') inputRefs.current[0]?.focus();
  }, [step]);

  const handleOtpChange = (index: number, value: string) => {
    if (!/^[0-9]*$/.test(value)) return;
    const newOtp = [...otp];
    newOtp[index] = value;
    setOtp(newOtp);
    if (value && index < 5) inputRefs.current[index + 1]?.focus();
  };

  const handleOtpKeyDown = (index: number, e: React.KeyboardEvent<HTMLInputElement>) => {
    if (e.key === 'Backspace' && !otp[index] && index > 0) {
      inputRefs.current[index - 1]?.focus();
    }
  };

  const handleOtpPaste = (e: React.ClipboardEvent) => {
    const pasted = e.clipboardData.getData('text').replace(/\D/g, '').slice(0, 6);
    if (pasted.length === 6) {
      setOtp(pasted.split(''));
      inputRefs.current[5]?.focus();
    }
    e.preventDefault();
  };

  const handleVerifyOtp = async (e: React.FormEvent) => {
    e.preventDefault();
    const code = otp.join('');
    if (code.length !== 6) {
      setError('Please enter the full 6-digit code.');
      return;
    }
    setError('');
    setLoading(true);
    try {
      await apiClient.post('/auth/verify-reset-otp', { identifier, code });
      setStep('password');
    } catch (err: unknown) {
      const errorObj = err as { response?: { data?: { error?: string } } };
      setError(errorObj.response?.data?.error || 'Invalid or expired code.');
    } finally {
      setLoading(false);
    }
  };

  const handleResendOtp = async () => {
    if (!identifier) return;
    setResendLoading(true);
    setResendMessage('');
    setError('');
    try {
      await apiClient.post('/auth/forgot-password', { identifier });
      setResendMessage('Code resent! Check your email.');
      setResendCooldown(30);
      setTimeout(() => setResendMessage(''), 3000);
    } catch (err: unknown) {
      const errorObj = err as { response?: { data?: { error?: string } } };
      setError(errorObj.response?.data?.error || 'Failed to resend code. Please try again.');
    } finally {
      setResendLoading(false);
    }
  };

  const handleResetPassword = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!password || password.length < 8) {
      setError('Password must be at least 8 characters.');
      return;
    }
    if (password !== confirmPassword) {
      setError('Passwords do not match.');
      return;
    }
    setError('');
    setLoading(true);
    try {
      await apiClient.post('/auth/reset-password', { identifier, code: otp.join(''), newPassword: password });
      setSuccess(true);
      setTimeout(() => navigate('/login'), 2500);
    } catch (err: unknown) {
      const errorObj = err as { response?: { data?: { error?: string } } };
      setError(errorObj.response?.data?.error || 'Reset failed. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  if (!identifier) return null;

  if (success) {
    return (
      <div className="relative h-screen w-full flex items-center justify-center p-4 bg-[#050505] font-sans overflow-hidden">
        <div className="relative z-10 w-full max-w-[480px] bg-[#0c0c0e] border border-white/[0.08] rounded-3xl shadow-[0_0_80px_rgba(0,0,0,0.8)] p-6 sm:p-10 text-center">
          <div className="h-12 w-12 bg-emerald-500/10 border border-emerald-500/20 rounded-2xl flex items-center justify-center mx-auto mb-4">
            <ShieldCheck className="h-6 w-6 text-emerald-400" />
          </div>
          <h2 className="font-display text-2xl font-bold text-white mb-2">Password Reset Successful</h2>
          <p className="text-zinc-400 text-sm">You will be redirected to the login page shortly.</p>
        </div>
      </div>
    );
  }

  return (
    <div className="relative min-h-screen w-full flex items-center justify-center p-4 bg-[#050505] font-sans overflow-y-auto">
      <div className="fixed top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[800px] h-[800px] bg-white/5 rounded-full blur-[120px] pointer-events-none" />

      <div className="relative z-10 w-full max-w-[460px] bg-[#0c0c0e] border border-white/[0.08] rounded-3xl shadow-[0_0_80px_rgba(0,0,0,0.8)] p-6 sm:p-10 my-6">
        <div className="flex flex-col items-center text-center">

          {/* Step indicator */}
          <div className="flex items-center gap-2 mb-6">
            <div className={`flex items-center justify-center w-7 h-7 rounded-full text-[11px] font-bold border transition-colors ${step === 'otp' ? 'bg-white text-black border-white' : 'bg-emerald-500/20 text-emerald-400 border-emerald-500/30'}`}>
              {step === 'otp' ? '1' : 'Γ£ô'}
            </div>
            <div className="w-8 h-px bg-white/20" />
            <div className={`flex items-center justify-center w-7 h-7 rounded-full text-[11px] font-bold border transition-colors ${step === 'password' ? 'bg-white text-black border-white' : 'bg-white/10 text-zinc-500 border-white/10'}`}>
              2
            </div>
          </div>

          <h2 className="font-display text-2xl sm:text-3xl font-bold tracking-tight mb-2 text-white">
            {step === 'otp' ? 'Verify Code' : 'Set New Password'}
          </h2>
          {step === 'otp' && (
            <p className="text-zinc-400 text-[14px] mb-8 font-medium px-2">
              Enter the 6-digit code sent to <span className="text-white font-bold">{identifier}</span>
            </p>
          )}

          {error && (
            <div className="w-full mb-5 p-3 text-[13px] font-medium text-rose-300 bg-rose-500/10 border border-rose-500/20 rounded-lg flex items-center space-x-2 text-left">
              <div className="w-1.5 h-1.5 rounded-full bg-rose-500 shrink-0" />
              <span>{error}</span>
            </div>
          )}

          {/* ΓöÇΓöÇ Step 1: OTP ΓöÇΓöÇ */}
          {step === 'otp' && (
            <form className="w-full space-y-6" noValidate onSubmit={handleVerifyOtp}>
              <div className="space-y-1.5 text-left">
                <label className="block text-[11px] font-bold text-white uppercase tracking-widest text-center mb-3">
                  6-Digit Recovery Code
                </label>
                <div className="flex justify-between gap-2 max-w-[340px] mx-auto" onPaste={handleOtpPaste}>
                  {otp.map((digit, index) => (
                    <input
                      key={index}
                      ref={(el) => { inputRefs.current[index] = el; }}
                      type="text"
                      inputMode="numeric"
                      maxLength={1}
                      value={digit}
                      onChange={(e) => handleOtpChange(index, e.target.value)}
                      onKeyDown={(e) => handleOtpKeyDown(index, e)}
                      className="w-12 h-14 text-center text-2xl font-bold bg-[#050505] border border-white/10 rounded-xl focus:border-white/40 focus:ring-0 outline-none text-white transition-colors"
                    />
                  ))}
                </div>
              </div>

              <div className="pt-2">
                <button
                  type="submit"
                  disabled={loading || otp.join('').length !== 6}
                  className="relative w-full flex justify-center items-center py-3.5 px-4 text-[15px] font-bold rounded-lg text-black bg-white hover:bg-zinc-200 focus:outline-none transition-all duration-200 active:scale-[0.97] disabled:opacity-50 disabled:cursor-not-allowed"
                >
                  <span>{loading ? 'Verifying...' : 'Verify Code'}</span>
                  {!loading && <ArrowRight className="ml-2 h-4 w-4" strokeWidth={2.5} />}
                </button>
              </div>

              <div className="mt-4 text-center">
                <button
                  type="button"
                  onClick={handleResendOtp}
                  disabled={resendLoading || resendCooldown > 0}
                  className="text-[13px] font-medium text-white hover:text-zinc-300 transition-colors underline decoration-white/30 underline-offset-4 disabled:opacity-50 disabled:no-underline disabled:hover:text-white"
                >
                  {resendLoading ? 'Sending...' : 'Resend Code'}
                </button>
                {resendCooldown > 0 && (
                  <span className="text-[13px] text-zinc-500 font-medium ml-2">in {resendCooldown}s</span>
                )}
                {resendMessage && <p className="text-[12px] text-emerald-400 mt-2">{resendMessage}</p>}
              </div>
            </form>
          )}

          {/* ΓöÇΓöÇ Step 2: New Password ΓöÇΓöÇ */}
          {step === 'password' && (
            <form className="w-full space-y-5" noValidate onSubmit={handleResetPassword}>
              {/* New Password */}
              <div className="space-y-1.5 text-left">
                <label className="block text-[11px] font-bold text-white uppercase tracking-widest ml-1">
                  New Password
                </label>
                <div className="relative">
                  <div className="absolute inset-y-0 left-0 pl-3.5 flex items-center pointer-events-none">
                    <LockKeyhole className="h-4 w-4 text-zinc-500" strokeWidth={2} />
                  </div>
                  <input
                    id="new-password"
                    name="new-password"
                    autoComplete="new-password"
                    type={showPassword ? 'text' : 'password'}
                    required
                    className="w-full pl-10 pr-10 py-2.5 bg-[#050505] border border-white/10 rounded-lg focus:border-white/30 focus:ring-0 outline-none transition-colors text-[14px] font-medium text-white placeholder-zinc-600"
                    placeholder="ΓÇóΓÇóΓÇóΓÇóΓÇóΓÇóΓÇóΓÇó"
                    value={password}
                    onChange={(e) => setPassword(e.target.value)}
                  />
                  <button
                    type="button"
                    onClick={() => setShowPassword(!showPassword)}
                    className="absolute inset-y-0 right-0 pr-3.5 flex items-center text-zinc-500 hover:text-zinc-300 transition-colors"
                    tabIndex={-1}
                  >
                    {showPassword ? <EyeOff className="h-4 w-4" strokeWidth={2} /> : <Eye className="h-4 w-4" strokeWidth={2} />}
                  </button>
                </div>
              </div>

              {/* Confirm Password */}
              <div className="space-y-1.5 text-left">
                <label className="block text-[11px] font-bold text-white uppercase tracking-widest ml-1">
                  Confirm Password
                </label>
                <div className="relative">
                  <div className="absolute inset-y-0 left-0 pl-3.5 flex items-center pointer-events-none">
                    <LockKeyhole className="h-4 w-4 text-zinc-500" strokeWidth={2} />
                  </div>
                  <input
                    id="confirm-password"
                    name="confirm-password"
                    autoComplete="new-password"
                    type={showConfirm ? 'text' : 'password'}
                    required
                    className={`w-full pl-10 pr-10 py-2.5 bg-[#050505] border rounded-lg focus:ring-0 outline-none transition-colors text-[14px] font-medium text-white placeholder-zinc-600 ${
                      confirmPassword && confirmPassword !== password
                        ? 'border-rose-500/50 focus:border-rose-500/70'
                        : confirmPassword && confirmPassword === password
                        ? 'border-emerald-500/40 focus:border-emerald-500/60'
                        : 'border-white/10 focus:border-white/30'
                    }`}
                    placeholder="ΓÇóΓÇóΓÇóΓÇóΓÇóΓÇóΓÇóΓÇó"
                    value={confirmPassword}
                    onChange={(e) => setConfirmPassword(e.target.value)}
                  />
                  <button
                    type="button"
                    onClick={() => setShowConfirm(!showConfirm)}
                    className="absolute inset-y-0 right-0 pr-3.5 flex items-center text-zinc-500 hover:text-zinc-300 transition-colors"
                    tabIndex={-1}
                  >
                    {showConfirm ? <EyeOff className="h-4 w-4" strokeWidth={2} /> : <Eye className="h-4 w-4" strokeWidth={2} />}
                  </button>
                </div>
                {confirmPassword && confirmPassword !== password && (
                  <p className="text-[12px] font-medium text-rose-400 ml-1 mt-1">Passwords do not match.</p>
                )}
                {confirmPassword && confirmPassword === password && (
                  <p className="text-[12px] font-medium text-emerald-400 ml-1 mt-1">Passwords match Γ£ô</p>
                )}
              </div>

              <div className="pt-1 relative group">
                <button
                  type="submit"
                  disabled={loading || password.length < 8 || password !== confirmPassword}
                  className="relative w-full flex justify-center items-center py-3.5 px-4 text-[15px] font-bold rounded-lg text-black bg-white hover:bg-zinc-200 focus:outline-none transition-all duration-200 active:scale-[0.97] disabled:opacity-50 disabled:cursor-not-allowed"
                >
                  <span>{loading ? 'Resetting...' : 'Reset Password'}</span>
                  {!loading && <ArrowRight className="ml-2 h-4 w-4" strokeWidth={2.5} />}
                </button>
                {/* Tooltip for weak password (less than 8 chars) */}
                {password.length > 0 && password.length < 8 && (
                  <div className="absolute bottom-full mb-3 left-1/2 -translate-x-1/2 w-max px-3 py-1.5 bg-zinc-800 text-xs font-medium text-white rounded-lg shadow-lg opacity-0 invisible group-hover:opacity-100 group-hover:visible transition-all duration-200 border border-zinc-700 pointer-events-none before:absolute before:top-full before:left-1/2 before:-translate-x-1/2 before:border-4 before:border-transparent before:border-t-zinc-800">
                    Choose a strong new password for your account
                  </div>
                )}
              </div>
            </form>
          )}
        </div>
      </div>
    </div>
  );
};

