import React, { useState, useEffect } from 'react';
import { X, Search, Check, Plus } from 'lucide-react';
import { apiClient } from '../../../shared/api/axios';
import { CurrencySelector } from '../../../shared/components/CurrencySelector';
import { getCurrencyData } from '../../../shared/constants/currencies';
import { useAuthStore } from '../../../app/store/useAuthStore';

interface Split {
  userId: string;
  amount: number;
}

interface ExpenseModalProps {
  isOpen: boolean;
  onClose: () => void;
  groupId?: string;
  groupType?: string;
  groupMembers?: any[];
  expenseToEdit?: any;  // If provided, we are in edit mode
  onSuccess: () => void;
  defaultDueDay?: number;
}

export const ExpenseModal: React.FC<ExpenseModalProps> = ({ 
  isOpen, onClose, groupId, groupType, groupMembers = [], expenseToEdit, onSuccess, defaultDueDay 
}) => {
  const [description, setDescription] = useState('');
  const [amount, setAmount] = useState<string>('');
  const [currency, setCurrency] = useState('INR');
  const [expenseDate, setExpenseDate] = useState(new Date().toISOString().split('T')[0]);
  const [dueDate, setDueDate] = useState('');
  const currentUser = useAuthStore(state => state.user);
  const [category, setCategory] = useState('');
  const [paidBy, setPaidBy] = useState('');
  const [involvedIds, setInvolvedIds] = useState<string[]>([]);
  const [loading, setLoading] = useState(false);
  const [isRecurring, setIsRecurring] = useState(false);
  const [frequency, setFrequency] = useState<'daily' | 'weekly' | 'monthly' | 'yearly'>('monthly');
  const [memberFilterSearch, setMemberFilterSearch] = useState('');
  const [isMemberSearchOpen, setIsMemberSearchOpen] = useState(false);

  // Initialize paidBy and involvedIds when modal opens or members change
  useEffect(() => {
    if (expenseToEdit) {
      setDescription(expenseToEdit.description);
      setAmount(expenseToEdit.amount.toString());
      setCurrency(expenseToEdit.currency);
      setCategory(expenseToEdit.category || '');
      setDueDate(expenseToEdit.due_date ? expenseToEdit.due_date.substring(0, 10) : '');
      setPaidBy(expenseToEdit.paid_by || getMemberId(groupMembers[0]));
      // Default all members as involved
      setInvolvedIds(groupMembers.map(m => getMemberId(m)));
    } else {
      setDescription('');
      setAmount('');
      setCategory('');
      setDueDate('');
      setPaidBy(getMemberId(groupMembers[0]));
      setInvolvedIds(groupMembers.map(m => getMemberId(m)));
      setExpenseDate(new Date().toISOString().split('T')[0]);

      // Default paidBy to current user if they are in the group, otherwise first member
      const userMember = groupMembers.find(m => getMemberId(m) === currentUser?.id);
      setPaidBy(userMember ? getMemberId(userMember) : getMemberId(groupMembers[0]));
      if (defaultDueDay) {
        const today = new Date();
        let targetMonth = today.getMonth();
        let targetYear = today.getFullYear();

        // If today's day is already past the due day, set for next month
        if (today.getDate() > defaultDueDay) {
          targetMonth += 1;
          if (targetMonth > 11) {
            targetMonth = 0;
            targetYear += 1;
          }
        }

        // Create the date (handle 31st on months with 30 days by using last day of month)
        const d = new Date(targetYear, targetMonth, defaultDueDay);
        // If d.getMonth() !== targetMonth, it overflowed (e.g. Feb 30 -> Mar 2), so fix it
        if (d.getMonth() !== (targetMonth % 12 + (targetMonth < 0 ? 12 : 0)) % 12) {
           d.setDate(0); // Last day of target month
        }
        setDueDate(d.toISOString().split('T')[0]);
      } else {
        setDueDate('');
      }
    }
  }, [expenseToEdit, isOpen, groupMembers.length]);

  const getMemberId = (m: any) => m?.user_id || m?.id || '';
  const getMemberName = (m: any) => m?.display_name || m?.name || (getMemberId(m) === 'me' ? 'You' : getMemberId(m));

  const categorySuggestions = React.useMemo(() => {
    if (!groupType || groupType === 'other') return [];
    if (groupType === 'rent') return ['House Rent', 'Water Rent', 'Electricity Rent', 'Maintenance'];
    if (groupType === 'trip') return ['Food', 'Travel', 'Accommodation', 'Activities'];
    return [];
  }, [groupType]);

  if (!isOpen) return null;

  const toggleInvolved = (memberId: string) => {
    if (involvedIds.includes(memberId)) {
      if (involvedIds.length <= 1) return; // Must keep at least 1
      setInvolvedIds(involvedIds.filter(id => id !== memberId));
    } else {
      setInvolvedIds([...involvedIds, memberId]);
    }
  };

  const selectAllMembers = () => {
    setInvolvedIds(groupMembers.map(m => getMemberId(m)));
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    try {
      const splitAmount = parseFloat(amount) / involvedIds.length;
      const splits = involvedIds.map(uid => ({ userId: uid, amount: splitAmount }));

      const payload = {
        groupId,
        paidBy: paidBy || getMemberId(groupMembers[0]),
        amount: parseFloat(amount),
        currency,
        description,
        splitType: 'equal',
        category,
        dueDate: dueDate || undefined,
        splits,
        date: expenseDate
      };

      if (expenseToEdit) {
        await apiClient.put(`/expenses/${expenseToEdit.id}`, payload);
      } else {
        await apiClient.post('/expenses', payload);
        if (isRecurring) {
           await apiClient.post('/expenses/recurring', {
             groupId,
             template: { ...payload, splitType: 'equal' }, // Simplified for now
             frequency,
             is_active: true
           });
        }
      }
      onSuccess();
      onClose();
    } catch (err) {
      console.error(err);
      alert('Failed to save expense');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm">
      <div className="bg-zinc-900 border border-white/10 rounded-2xl p-6 w-full max-w-md shadow-2xl relative max-h-[90vh] flex flex-col">
        <button onClick={onClose} className="absolute right-4 top-4 text-zinc-400 hover:text-white">
          <X className="w-5 h-5" />
        </button>
        <h2 className="text-xl font-bold text-white mb-6 shrink-0">
          {expenseToEdit ? 'Edit Expense' : 'Add Expense'}
        </h2>

        <form onSubmit={handleSubmit} className="flex flex-col gap-4 overflow-y-auto custom-scrollbar flex-1 pr-1">
          <div>
            <label className="block text-xs text-zinc-400 mb-1 font-medium">Description</label>
            <input 
              required
              autoFocus
              type="text" 
              value={description}
              onChange={(e) => setDescription(e.target.value)}
              className="w-full bg-black/50 border border-white/10 rounded-lg p-3 text-white placeholder-zinc-600 focus:outline-none focus:border-indigo-500 transition-colors"
              placeholder="What was this expense for?"
            />
          </div>

          <div className="flex gap-4">
            <div className="flex-1">
              <label className="block text-xs text-zinc-400 mb-1 font-medium">Amount</label>
              <input 
                required
                type="number" 
                min="1"
                value={amount}
                onChange={(e) => setAmount(e.target.value)} onWheel={e => e.currentTarget.blur()}
                className="w-full bg-black/50 border border-white/10 rounded-lg px-4 py-3 text-white focus:outline-none focus:border-indigo-500 transition-colors font-bold"
                placeholder="0.00"
              />
            </div>
            <div className="w-40">
               <label className="block text-xs text-zinc-400 mb-1 font-medium">Currency</label>
               <CurrencySelector value={currency} onChange={setCurrency} />
            </div>
          </div>

          {/* Who Paid */}
          <div>
            <label className="block text-xs text-zinc-400 mb-1 font-medium">Paid By</label>
            <select
              value={paidBy}
              onChange={(e) => setPaidBy(e.target.value)}
              className="w-full bg-black/50 border border-white/10 rounded-lg p-3 text-white focus:outline-none focus:border-indigo-500 transition-colors"
            >
              {groupMembers.map(m => (
                <option key={getMemberId(m)} value={getMemberId(m)}>
                  {getMemberName(m)}
                </option>
              ))}
            </select>
          </div>

          {/* Split Among */}
          <div>
            <div className="flex items-center justify-between mb-1">
              <div className="flex items-center gap-2">
                <label className="block text-xs text-zinc-400 font-medium">Split Among</label>
                <button 
                  type="button" 
                  onClick={() => setIsMemberSearchOpen(!isMemberSearchOpen)}
                  className={`p-1 rounded-md transition-colors ${isMemberSearchOpen ? 'bg-indigo-500/10 text-indigo-400' : 'text-zinc-500 hover:text-white hover:bg-white/5'}`}
                >
                  <Search className="w-3 h-3" />
                </button>
              </div>
              <button
                type="button"
                onClick={selectAllMembers}
                className="text-[10px] text-indigo-400 hover:text-indigo-300 font-semibold transition-colors"
              >
                Select All
              </button>
            </div>

            {isMemberSearchOpen && (
              <div className="relative mb-3 animate-in slide-in-from-top-1 duration-200">
                <input 
                  autoFocus
                  type="text"
                  value={memberFilterSearch}
                  onChange={e => setMemberFilterSearch(e.target.value)}
                  className="w-full bg-black/30 border border-white/10 rounded-lg pl-3 pr-8 py-1.5 text-[11px] text-white focus:outline-none focus:border-indigo-500/50"
                  placeholder="Filter members..."
                />
                {memberFilterSearch && (
                  <button 
                    onClick={() => setMemberFilterSearch('')}
                    className="absolute right-2 top-1.5 text-zinc-500 hover:text-white"
                  >
                    <X className="w-3 h-3" />
                  </button>
                )}
              </div>
            )}

            <div className="flex flex-wrap gap-2">
              {groupMembers
                .filter(m => getMemberName(m).toLowerCase().includes(memberFilterSearch.toLowerCase()))
                .map(m => {
                  const mid = getMemberId(m);
                  const isSelected = involvedIds.includes(mid);
                  return (
                    <button
                      type="button"
                      key={mid}
                      onClick={() => toggleInvolved(mid)}
                      className={`px-3 py-1.5 rounded-full text-xs font-bold transition-all border ${
                        isSelected
                          ? 'bg-indigo-500 border-indigo-400 text-white shadow-lg shadow-indigo-500/20'
                          : 'bg-transparent border-white/10 text-zinc-500 hover:border-white/30'
                      }`}
                    >
                      {getMemberName(m)}
                    </button>
                  );
                })}
            </div>
            {amount && involvedIds.length > 0 && (
              <p className="text-[11px] text-zinc-500 mt-2">
                Each person pays <span className="text-white font-bold">{currency} {(parseFloat(amount) / involvedIds.length).toFixed(2)}</span>
              </p>
            )}
          </div>

          <div>
             <label className="block text-xs text-zinc-400 mb-1 font-medium">Category</label>
             <input 
               type="text" 
               value={category}
               onChange={(e) => setCategory(e.target.value)}
               className="w-full bg-black/50 border border-white/10 rounded-lg p-3 text-white placeholder-zinc-600 focus:outline-none focus:border-indigo-500 transition-colors"
               placeholder="e.g. Food"
             />
             {categorySuggestions.length > 0 && (
               <div className="flex flex-wrap gap-2 mt-2">
                 {categorySuggestions.map(s => (
                   <button 
                     key={s} 
                     type="button"
                     onClick={() => setCategory(s)}
                     className="text-[11px] font-medium px-2 py-1 bg-white/5 hover:bg-indigo-500/20 border border-white/5 rounded text-zinc-300 transition-colors"
                   >
                     {s}
                   </button>
                 ))}
               </div>
             )}
          </div>

          <div>
             <label className="block text-xs text-zinc-400 mb-1 font-medium">Date of Expense</label>
             <input 
               type="date" 
               required
               value={expenseDate}
               onChange={(e) => setExpenseDate(e.target.value)}
               className="w-full bg-black/50 border border-white/10 rounded-lg p-3 text-white focus:outline-none focus:border-indigo-500 transition-colors"
             />
          </div>

          <div>
             <label className="block text-xs text-zinc-400 mb-1 font-medium">Due Date (Optional)</label>
             <input 
               type="date" 
               value={dueDate}
               onChange={(e) => setDueDate(e.target.value)}
               className="w-full bg-black/50 border border-white/10 rounded-lg p-3 text-white focus:outline-none focus:border-indigo-500 transition-colors"
             />
          </div>

          {groupId && (
            <div className="pt-2 border-t border-white/5 space-y-4">
               <div className="flex items-center justify-between">
                  <div className="flex flex-col">
                     <span className="text-sm font-bold text-white">Make Recurring</span>
                     <span className="text-[10px] text-zinc-500">Auto-post this expense periodically</span>
                  </div>
                  <button 
                    type="button"
                    onClick={() => setIsRecurring(!isRecurring)}
                    className={`w-10 h-5 rounded-full relative transition-colors ${isRecurring ? 'bg-indigo-500' : 'bg-white/10'}`}
                  >
                    <div className={`absolute top-1 w-3 h-3 bg-white rounded-full transition-all ${isRecurring ? 'left-6' : 'left-1'}`} />
                  </button>
               </div>

               {isRecurring && (
                 <div className="flex gap-2 animate-in slide-in-from-top-2 duration-300">
                    {['daily', 'weekly', 'monthly', 'yearly'].map(f => (
                      <button 
                        key={f} 
                        type="button"
                        onClick={() => setFrequency(f as any)}
                        className={`flex-1 py-2 rounded-lg text-[10px] font-bold uppercase tracking-wider transition-all border ${frequency === f ? 'bg-white/10 border-white/20 text-white' : 'border-transparent text-zinc-600 hover:text-zinc-400'}`}
                      >
                        {f}
                      </button>
                    ))}
                 </div>
               )}
            </div>
          )}

          <button 
            type="submit" 
            disabled={loading}
            className="w-full mt-4 bg-indigo-500 hover:bg-indigo-400 text-white font-bold py-3 rounded-xl transition-all shadow-lg shadow-indigo-500/20 active:scale-[0.98] disabled:opacity-50 shrink-0"
          >
            {loading ? 'Saving...' : (expenseToEdit ? 'Save Changes' : 'Add Expense')}
          </button>
        </form>
      </div>
    </div>
  );
};

import { useState, useEffect, useRef } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { apiClient } from '../../../shared/api/axios';
import { useSocket } from '../../../shared/hooks/useSocket';
import { useAuthStore } from '../../../app/store/useAuthStore';
import { ArrowLeft, Send, Receipt, Wallet, Banknote, Edit2, Trash2, Bell, Loader2 } from 'lucide-react';
import { ExpenseModal } from '../../expenses/components/ExpenseModal';

interface FriendExpense {
  id: string;
  description: string;
  amount: number;
  paid_by: string;
  paid_by_name: string;
  created_at: string;
  due_date?: string;
  is_settled: boolean;
}

interface FriendDetailData {
  friend: { id: string; display_name: string; nickname?: string };
  balance: { netBalance: number; totalOwed: number; totalOwe: number };
  expenses: FriendExpense[];
  mutualGroups: { id: string; name: string }[];
}

interface ChatMessage {
  id: string;
  sender_id: string;
  content: string;
  created_at: string;
}

export const FriendDetail = () => {
  const { id } = useParams();
  const navigate = useNavigate();
  const { emit, on } = useSocket();
  const currentUser = useAuthStore(s => s.user);
  const [detail, setDetail] = useState<FriendDetailData | null>(null);
  const [chat, setChat] = useState<ChatMessage[]>([]);
  const [msgInput, setMsgInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const [isExpenseModalOpen, setExpenseModalOpen] = useState(false);
  const [expenseToEdit, setExpenseToEdit] = useState<FriendExpense | null>(null);
  const [loadingReminders, setLoadingReminders] = useState<Record<string, boolean>>({});
  const [isEditingNickname, setIsEditingNickname] = useState(false);
  const [nicknameInput, setNicknameInput] = useState('');
  const typingTimeoutRef = useRef<ReturnType<typeof setTimeout> | null>(null);
  const chatEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (id) {
      // Fetch detail & chat history
      Promise.all([
        apiClient.get(`/friends/${id}`),
        apiClient.get(`/chat/${id}`)
      ]).then(([detailRes, chatRes]) => {
        setDetail({
          ...detailRes.data,
          // Sort expenses by created_at desc just in case
          expenses: detailRes.data.expenses?.sort((a: any, b: any) => new Date(b.created_at).getTime() - new Date(a.created_at).getTime())
        });
        setChat(chatRes.data);
      }).catch(console.error);

      // Join chat room
      emit('join_conversation', id);
    }
    return () => {
      if (id) emit('leave_conversation', id);
    };
  }, [id, emit]);

  useEffect(() => {
    const unsub1 = on('new_message', (msg) => {
      setChat(prev => [...prev, msg]);
      emit('mark_read', id);
    });
    const unsub2 = on('user_typing', () => setIsTyping(true));
    const unsub3 = on('user_stop_typing', () => setIsTyping(false));
    
    return () => {
      unsub1();
      unsub2();
      unsub3();
    };
  }, [on, emit, id]);

  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [chat]);

  const handleInput = (val: string) => {
    setMsgInput(val);
    emit('typing', id);
    if (typingTimeoutRef.current) clearTimeout(typingTimeoutRef.current);
    typingTimeoutRef.current = setTimeout(() => {
      emit('stop_typing', id);
    }, 1500);
  };

  const handleSend = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!msgInput.trim()) return;
    try {
      if (typingTimeoutRef.current) clearTimeout(typingTimeoutRef.current);
      emit('stop_typing', id);
      await apiClient.post(`/chat/${id}`, { content: msgInput });
      setMsgInput('');
    } catch (err) {
      console.error(err);
    }
  };

  const handleDeleteExpense = async (expenseId: string) => {
    if (!confirm('Are you sure you want to delete this expense?')) return;
    try {
      await apiClient.delete(`/expenses/${expenseId}`);
      setDetail((prev: any) => ({ ...prev, expenses: prev.expenses.filter((e: any) => e.id !== expenseId) }));
    } catch (err) {
      console.error('Delete failed', err);
    }
  };

  const handleRemindExpense = async (expenseId: string) => {
    setLoadingReminders(prev => ({ ...prev, [expenseId]: true }));
    try {
      await apiClient.post(`/expenses/${expenseId}/remind`);
      alert('Reminder sent!');
    } catch (err) {
      console.error('Reminder failed', err);
    } finally {
      setLoadingReminders(prev => ({ ...prev, [expenseId]: false }));
    }
  };

  const refreshData = () => {
    apiClient.get(`/friends/${id}`).then((res) => {
      setDetail(res.data);
      setNicknameInput(res.data.friend.nickname || '');
    });
  };

  const handleUpdateNickname = async () => {
    try {
      await apiClient.post('/friends/nickname', { friendId: id, nickname: nicknameInput || null });
      setIsEditingNickname(false);
      refreshData();
    } catch (err) {
      console.error(err);
    }
  };

  const handleSettleAll = async () => {
    if (!confirm(`Are you sure you want to settle all debts with ${detail.friend.display_name}?`)) return;
    try {
      await apiClient.post('/settlements/settle-all-mutual', { friendId: id });
      refreshData();
    } catch (err) {
      console.error(err);
    }
  };

  const handleSettleSpecificExpense = async (expenseId: string) => {
    try {
      await apiClient.post(`/expenses/${expenseId}/settle`);
      refreshData();
    } catch (err) {
      console.error('Settle specific expense failed', err);
    }
  };

  const handleSettleSpecificExpense = async (expenseId: string) => {
    try {
      await apiClient.post(`/expenses/${expenseId}/settle`);
      refreshData();
    } catch (err) {
      console.error('Settle specific expense failed', err);
    }
  };

  if (!detail) return <div className="p-8 text-white">Loading...</div>;

  return (
    <div className="flex flex-col h-full bg-black/40 relative w-full shadow-2xl overflow-hidden backdrop-blur-md">
       <div className="absolute inset-0 flex items-center justify-center pointer-events-none opacity-30">
           <div className="w-[500px] h-[500px] bg-indigo-500/10 rounded-full blur-[100px]" />
       </div>

       {/* HEADER */}
       <div className="p-4 border-b border-white/10 flex items-center justify-between z-10 bg-black/50 backdrop-blur-xl">
         <div className="flex items-center gap-4">
            <button onClick={() => navigate('/friends')} className="text-zinc-400 hover:text-white transition-colors">
              <ArrowLeft className="w-5 h-5" />
            </button>
             <div className="flex flex-col">
               <div className="flex items-center gap-2">
                 {isEditingNickname ? (
                   <input
                     autoFocus
                     value={nicknameInput}
                     onChange={e => setNicknameInput(e.target.value)}
                     onBlur={handleUpdateNickname}
                     onKeyDown={e => e.key === 'Enter' && handleUpdateNickname()}
                     className="bg-white/5 border border-white/20 rounded px-2 py-0.5 text-white text-lg font-bold focus:outline-none"
                   />
                 ) : (
                   <h2 className="text-lg font-bold text-white flex items-center gap-2">
                     {detail.friend.nickname || detail.friend.display_name}
                     <button onClick={() => setIsEditingNickname(true)} className="p-1 hover:bg-white/10 rounded transition-colors">
                       <Edit2 className="w-3.5 h-3.5 text-zinc-500" />
                     </button>
                   </h2>
                 )}
               </div>
               
               <div className="flex items-center gap-3">
                 {detail.friend.nickname && (
                   <span className="text-[11px] text-zinc-500 font-medium">{detail.friend.display_name}</span>
                 )}
                 {detail.mutualGroups?.length > 0 && (
                   <div className="flex items-center gap-1.5 ml-2 border-l border-white/10 pl-3 flex-wrap">
                     <span className="text-[10px] text-zinc-500 font-bold uppercase tracking-wider">
                       {detail.mutualGroups.length} shared {detail.mutualGroups.length === 1 ? 'group' : 'groups'}:
                     </span>
                     {detail.mutualGroups.map((g: any) => (
                       <div key={g.id} className="text-[10px] font-bold bg-white/5 border border-white/10 text-zinc-400 px-2 py-0.5 rounded-full cursor-pointer hover:bg-white/10 transition-colors" onClick={() => navigate(`/groups/${g.id}`)}>
                         {g.name}
                       </div>
                     ))}
                   </div>
                 )}
               </div>
            </div>
          </div>
         <div className="flex gap-3">
           <button 
             onClick={() => { setExpenseToEdit(null); setExpenseModalOpen(true); }}
             className="px-4 py-2 bg-white/5 hover:bg-white/10 border border-white/10 rounded-lg text-sm text-white font-medium transition-colors flex items-center gap-2"
           >
             <Receipt className="w-4 h-4" /> Add Expense
           </button>
            <button 
              onClick={handleSettleAll}
              disabled={detail.balance.netBalance === 0}
              className={`px-4 py-2 rounded-lg text-sm font-bold transition-colors flex items-center gap-2 ${
                detail.balance.netBalance === 0 
                  ? 'bg-zinc-800 text-zinc-500 cursor-not-allowed shadow-none'
                  : 'bg-amber-500 hover:bg-amber-400 text-black shadow-lg shadow-amber-500/20'
              }`}
            >
              <Banknote className="w-4 h-4" /> Settle Up
            </button>
         </div>
       </div>

       <div className="flex flex-1 overflow-hidden z-10">
         {/* LEFT: Balance & Expenses */}
         <div className="w-[400px] border-r border-white/5 flex flex-col bg-black/20">
           {/* Balance Card */}
           <div className="p-6 border-b border-white/5">
             <h3 className="text-[13px] font-semibold text-zinc-500 uppercase tracking-widest mb-4">Mutual Balance</h3>
             <div className="bg-white/5 border border-white/10 rounded-2xl p-5 relative overflow-hidden mb-4">
                <Wallet className="absolute right-[-10px] bottom-[-10px] w-24 h-24 text-white/5 pointer-events-none" />
                <div className="flex flex-col gap-1 relative z-10">
                  {detail.balance.netBalance === 0 ? (
                    <span className="text-2xl font-bold text-white">All settled up!</span>
                  ) : detail.balance.netBalance > 0 ? (
                    <>
                      <span className="text-sm font-medium text-emerald-400/80">Owes you</span>
                      <span className="text-3xl font-black text-emerald-400 tracking-tight">Γé╣{detail.balance.netBalance}</span>
                    </>
                  ) : (
                    <>
                      <span className="text-sm font-medium text-rose-400/80">You owe</span>
                      <span className="text-3xl font-black text-rose-400 tracking-tight">Γé╣{Math.abs(detail.balance.netBalance)}</span>
                    </>
                  )}
                </div>
             </div>

             {detail.balance.netBalance !== 0 && (
               <div className="bg-indigo-500/10 border border-indigo-500/20 rounded-xl p-3 mb-4 cursor-pointer hover:bg-indigo-500/20 transition-colors">
                 <p className="text-xs font-medium text-indigo-300 mb-1 flex items-center justify-between">
                   <span>Γ£¿ Debt Simplification</span>
                 </p>
                 <p className="text-[11px] text-indigo-400/80 leading-snug">
                   You both share mutual friends. Suggesting an optimized route: they can pay Rahul directly to resolve this amount!
                 </p>
               </div>
             )}

             <div className="grid grid-cols-2 gap-3">
               <div className="bg-white/[0.03] border border-white/5 rounded-xl p-3 flex flex-col items-center text-center">
                  <span className="text-[11px] text-zinc-500 font-bold uppercase mb-1">Total Spent</span>
                  <span className="text-lg font-black text-white">Γé╣{detail.stats?.totalSpentTogether || 0}</span>
               </div>
               <div className="bg-white/[0.03] border border-white/5 rounded-xl p-3 flex flex-col items-center text-center">
                  <span className="text-[11px] text-zinc-500 font-bold uppercase mb-1">Top Category</span>
                  <span className="text-sm font-bold text-amber-500 truncate w-full px-2" title={detail.stats?.mostCommonCategory || 'None'}>
                    {detail.stats?.mostCommonCategory || 'None'}
                  </span>
               </div>
             </div>
           </div>

           {/* Expenses Feed */}
           <div className="flex-1 overflow-y-auto custom-scrollbar p-6">
             <h3 className="text-[13px] font-semibold text-zinc-500 uppercase tracking-widest mb-4">Shared History</h3>
             <div className="flex flex-col gap-3">
               {detail.expenses.length === 0 ? (
                 <p className="text-sm text-zinc-600">No shared expenses found.</p>
               ) : (
                 detail.expenses.map((e: any) => (
                    <div key={e.id} className={`p-4 rounded-xl border ${e.is_settled ? 'border-emerald-500/20' : 'border-white/5'} bg-white/[0.02] hover:bg-white/[0.04] transition-colors group relative overflow-hidden`}>
                      <div className={`absolute left-0 top-0 bottom-0 w-1 transition-colors ${e.is_settled ? 'bg-emerald-500/50' : 'bg-indigo-500/0 group-hover:bg-indigo-500/50'}`} />
                      <div className="flex justify-between items-start mb-2 pl-1">
                        <div className="flex flex-col gap-1 pr-2">
                          <h4 className="text-[15px] font-medium text-white">{e.description}</h4>
                          <div className="flex items-center gap-1.5 mt-0.5">
                            <span className={`text-[9px] font-bold uppercase tracking-wider px-1.5 py-0.5 rounded-sm ${e.is_settled ? 'bg-emerald-500/10 text-emerald-400' : 'bg-zinc-500/10 text-zinc-400'}`}>
                               {e.is_settled ? 'Settled Up' : 'Not Settled Up'}
                            </span>
                          </div>
                        </div>
                        <div className="flex items-center gap-2 shrink-0">
                          {/* Action buttons (hover) */}
                          <div className="opacity-0 group-hover:opacity-100 transition-opacity flex gap-1.5 items-center">
                            {!e.is_settled && (
                               <button 
                                 onClick={() => handleSettleSpecificExpense(e.id)}
                                 className="px-2 py-1 bg-emerald-500/20 text-emerald-400 text-[10px] font-bold rounded hover:bg-emerald-500/40 tracking-wide uppercase" 
                                 title="Settle this specific activity"
                               >
                                 Settle Up
                               </button>
                            )}
                            <button 
                              onClick={() => handleRemindExpense(e.id)}
                              className="p-1.5 bg-indigo-500/20 text-indigo-400 rounded hover:bg-indigo-500/40" 
                              title="Send Reminder"
                            >
