             {/* Dynamic Center Content */}
             <div className="absolute inset-0 flex flex-col items-center justify-center pointer-events-none">
                {hoveredData ? (
                  <>
                    <span className="text-[10px] font-bold text-zinc-500 uppercase tracking-tighter mb-0.5">
                      {hoveredData[0]}
                    </span>
                    <span className="text-lg font-display font-black text-white">
                      Γé╣{Number(hoveredData[1]).toLocaleString()}
                    </span>
                  </>
                ) : (
                  <>
                    <span className="text-[10px] font-bold text-zinc-500 uppercase tracking-tighter mb-0.5">
                      Total
                    </span>
                    <span className="text-lg font-display font-black text-white">
                      Γé╣{total.toLocaleString()}
                    </span>
                  </>
                )}
             </div>
           </div>

           <div className="flex flex-wrap md:flex-col gap-x-6 gap-y-3 justify-center">
             {catEntries.map(([cat, amt], idx) => (
               <div 
                 key={cat} 
                 className={`flex items-center gap-2.5 transition-all duration-300 ${hoveredIndex === idx ? 'scale-110 translate-x-1' : ''}`}
                 onMouseEnter={() => setHoveredIndex(idx)}
                 onMouseLeave={() => setHoveredIndex(null)}
               >
                 <div 
                   className="w-3 h-3 rounded-full shadow-lg" 
                   style={{ 
                     backgroundColor: colors[idx % colors.length],
                     boxShadow: hoveredIndex === idx ? `0 0 12px ${colors[idx % colors.length]}44` : 'none'
                   }} 
                 />
                 <span className={`text-xs font-bold transition-colors ${hoveredIndex === idx ? 'text-white' : 'text-zinc-500'}`}>
                   {cat}
                 </span>
               </div>
             ))}
           </div>

           {/* New: Quick Mutual Summary adjacent to the chart */}
           <div className="flex flex-col gap-4 ml-auto pl-6 border-l border-white/5">
              <div className="flex flex-col">
                <span className="text-[10px] font-bold text-emerald-500/70 uppercase tracking-widest mb-1">Owes You</span>
                <span className="text-xl font-black text-emerald-400">Γé╣{totalOwedToMe}</span>
              </div>
              <div className="w-8 h-px bg-white/5" />
              <div className="flex flex-col">
                <span className="text-[10px] font-bold text-rose-500/70 uppercase tracking-widest mb-1">You Owe</span>
                <span className="text-xl font-black text-rose-400">Γé╣{totalIOwe}</span>
              </div>
           </div>
         </div>
      </div>
    );
  }

  // Horizontal Stacked Bar (Fallback for single category)
  return (
    <div className="mb-6 bg-black/20 p-5 rounded-2xl border border-white/5">
      <h4 className="text-sm font-bold text-white uppercase tracking-widest mb-4">Category Breakdown</h4>
      <div className="flex flex-col gap-3">
        {catEntries.map(([cat, amt], idx) => (
