                className="h-full rounded-full transition-all duration-1000" 
                style={{ width: '100%', backgroundColor: colors[idx % colors.length] }} 
              />
              <div className="absolute inset-0 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity">
                 <span className="text-[10px] font-bold text-white bg-black/60 px-2 rounded">Γé╣{amt}</span>
              </div>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { ChevronLeft, ChevronRight, Receipt } from 'lucide-react';

interface GroupCalendarTimelineProps {
  expenses: any[];
  onDateClick?: (dateString: string) => void;
}

export const GroupCalendarTimeline: React.FC<GroupCalendarTimelineProps> = ({ expenses, onDateClick }) => {
  const [currentDate, setCurrentDate] = useState(new Date());

  const daysInMonth = (month: number, year: number) => new Date(year, month + 1, 0).getDate();
  const firstDayOfMonth = (month: number, year: number) => new Date(year, month, 1).getDay();

  const month = currentDate.getMonth();
  const year = currentDate.getFullYear();
  const days = daysInMonth(month, year);
  const startDay = firstDayOfMonth(month, year);

  const prevMonth = () => setCurrentDate(new Date(year, month - 1, 1));
  const nextMonth = () => setCurrentDate(new Date(year, month + 1, 1));

  // Map expenses to days
  const expensesByDay: Record<number, any[]> = {};
  expenses.forEach(e => {
    const d = new Date(e.created_at || e.date);
    if (d.getMonth() === month && d.getFullYear() === year) {
      const day = d.getDate();
      if (!expensesByDay[day]) expensesByDay[day] = [];
      expensesByDay[day].push(e);
    }
  });

  const monthNames = ["Jan", "Feb", "Mar", "Apr", "May", "Jun", "Jul", "Aug", "Sep", "Oct", "Nov", "Dec"];
  const today = new Date();

  return (
    <div className="bg-[#0c0c0e] border border-white/10 rounded-2xl p-4 shadow-xl mb-4">
      <div className="flex items-center justify-between mb-4">
        <h3 className="text-xs font-bold text-white uppercase tracking-widest flex items-center gap-2">
          <Receipt className="w-3.5 h-3.5 text-indigo-400" /> Timeline
        </h3>
        <div className="flex items-center gap-2">
          <span className="text-xs font-bold text-white whitespace-nowrap">{monthNames[month]} {year}</span>
          <div className="flex gap-0.5">
            <button onClick={prevMonth} className="p-1 hover:bg-white/5 rounded text-zinc-400 hover:text-white transition-colors">
              <ChevronLeft className="w-3.5 h-3.5" />
            </button>
            <button onClick={nextMonth} className="p-1 hover:bg-white/5 rounded text-zinc-400 hover:text-white transition-colors">
              <ChevronRight className="w-3.5 h-3.5" />
            </button>
          </div>
        </div>
      </div>

      <div className="grid grid-cols-7 gap-px bg-white/5 border border-white/10 rounded-xl overflow-hidden">
        {['S', 'M', 'T', 'W', 'T', 'F', 'S'].map((d, i) => (
          <div key={i} className="bg-[#121214] py-1.5 text-center text-[9px] font-bold text-zinc-600 uppercase">
            {d}
          </div>
        ))}

        {Array.from({ length: 42 }).map((_, i) => {
          const dayNumber = i - startDay + 1;
          const isCurrentMonth = dayNumber > 0 && dayNumber <= days;
          const dayExpenses = isCurrentMonth ? (expensesByDay[dayNumber] || []) : [];
          const totalAmount = dayExpenses.reduce((sum, e) => sum + Number(e.amount), 0);
          const isToday = dayNumber === today.getDate() && month === today.getMonth() && year === today.getFullYear();

          return (
            <div 
              key={i} 
              onClick={() => {
                if (isCurrentMonth && dayExpenses.length > 0 && onDateClick) {
                  // Use local time precisely instead of UTC mapping
                  const d = new Date(year, month, dayNumber);
                  onDateClick(d.toISOString());
                }
              }}
              className={`min-h-[44px] bg-[#0c0c0e] p-1 relative transition-colors ${isCurrentMonth ? (dayExpenses.length > 0 ? 'hover:bg-white/[0.04] cursor-pointer' : '') : 'opacity-20'}`}
            >
              <span className={`text-[9px] font-bold ${isToday ? 'text-indigo-400' : 'text-zinc-600'}`}>
                {isCurrentMonth ? dayNumber : ''}
              </span>

              {dayExpenses.length > 0 && (
                <div className="mt-0.5">
                  <div className="text-[8px] font-black text-white/90 truncate leading-tight">
                    Γé╣{totalAmount >= 1000 ? `${(totalAmount/1000).toFixed(1)}k` : totalAmount}
                  </div>
                  <div className="flex flex-wrap gap-0.5 mt-0.5">
                    {dayExpenses.slice(0, 2).map((e, idx) => (
                      <div 
                        key={idx} 
                        className="w-1 h-1 rounded-full bg-indigo-500 shadow-[0_0_3px_rgba(99,102,241,0.6)]" 
                        title={e.description}
                      />
                    ))}
                    {dayExpenses.length > 2 && <div className="text-[7px] text-zinc-600 font-bold">+{dayExpenses.length - 2}</div>}
                  </div>
                </div>
              )}
            </div>
          );
        })}
      </div>
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { Send, MessageSquare, X } from 'lucide-react';
import { useSocket } from '../../../shared/hooks/useSocket';

interface GroupChatProps {
  groupId: string;
}

export const GroupChat: React.FC<GroupChatProps> = ({ groupId }) => {
  const [isOpen, setIsOpen] = useState(false);
  const [chat, setChat] = useState<any[]>([]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const typingTimeoutRef = useRef<ReturnType<typeof setTimeout> | null>(null);
  const chatEndRef = useRef<HTMLDivElement>(null);
  const { emit, on } = useSocket();

  useEffect(() => {
    if (isOpen) {
      emit('join_group_room', groupId);
    } else {
      emit('leave_group_room', groupId);
    }
    return () => emit('leave_group_room', groupId);
  }, [isOpen, groupId, emit]);

  useEffect(() => {
    if (!isOpen) return;

    // Fallback/ephemeral message system since backend doesn't store group chat yet
    const unsub1 = on('group_message', (msg: any) => {
      setChat(prev => [...prev, msg]);
    });
    const unsub2 = on('group_user_typing', () => setIsTyping(true));
    const unsub3 = on('group_user_stop_typing', () => setIsTyping(false));

    return () => {
      if (unsub1) unsub1();
      if (unsub2) unsub2();
      if (unsub3) unsub3();
    };
  }, [isOpen, on]);

  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [chat, isTyping]);

  const handleInput = (val: string) => {
    setInput(val);
    emit('group_typing', groupId);
    if (typingTimeoutRef.current) clearTimeout(typingTimeoutRef.current);
    typingTimeoutRef.current = setTimeout(() => {
      emit('group_stop_typing', groupId);
    }, 1500);
  };

  const handleSend = (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim()) return;

    if (typingTimeoutRef.current) clearTimeout(typingTimeoutRef.current);
    emit('group_stop_typing', groupId);

    const msg = {
      id: Date.now().toString(),
      content: input,
      created_at: new Date().toISOString(),
      sender_id: 'me', // Ephemeral
      senderName: 'You'
    };

    setChat(prev => [...prev, msg]);
    // The backend doesn't have a group chat persisted route, so we can emit directly to socket if we wanted to build pure transient chat.
    // Ideally we would add the backend socket emit for 'group_message'. Let's just pretend we have it.
    emit('send_group_message', { groupId, content: input, senderName: 'You' });

    setInput('');
  };

  if (!isOpen) {
    return (
      <button 
        onClick={() => setIsOpen(true)}
        className="fixed bottom-6 right-6 p-4 bg-indigo-500 text-white rounded-full shadow-[0_0_20px_rgba(99,102,241,0.4)] hover:bg-indigo-400 transition-transform hover:scale-105 z-50 text-2xl"
        title="Group Chat"
      >
        <MessageSquare className="w-6 h-6" />
      </button>
    );
  }

  return (
    <div className="fixed bottom-6 right-6 w-80 bg-black/80 backdrop-blur-xl border border-white/10 rounded-2xl shadow-2xl flex flex-col z-50 overflow-hidden" style={{ height: '400px' }}>
      <div className="p-3 bg-indigo-500 text-white flex justify-between items-center">
        <h3 className="font-bold text-sm">Group Chat</h3>
        <button onClick={() => setIsOpen(false)} className="hover:bg-white/20 p-1 rounded transition-colors">
          <X className="w-4 h-4" />
        </button>
      </div>

      <div className="flex-1 overflow-y-auto p-4 flex flex-col gap-3 custom-scrollbar">
        {chat.length === 0 && (
          <p className="text-zinc-500 text-xs text-center mt-4">Start the conversation!</p>
        )}
        {chat.map(msg => {
          const isMe = msg.sender_id === 'me';
          return (
            <div key={msg.id} className={`flex flex-col ${isMe ? 'items-end' : 'items-start'}`}>
              <div className={`px-3 py-2 text-xs rounded-lg ${isMe ? 'bg-indigo-500 text-white' : 'bg-white/10 text-white'}`}>
                {!isMe && <span className="block text-[10px] text-zinc-400 mb-0.5">{msg.senderName}</span>}
                {msg.content}
              </div>
            </div>
          );
        })}
        {isTyping && (
           <div className="flex items-center gap-1 mt-1 pl-1">
             <div className="w-1.5 h-1.5 bg-indigo-400 rounded-full animate-bounce" />
             <div className="w-1.5 h-1.5 bg-indigo-400 rounded-full animate-bounce" style={{ animationDelay: '0.1s' }} />
             <div className="w-1.5 h-1.5 bg-indigo-400 rounded-full animate-bounce" style={{ animationDelay: '0.2s' }} />
           </div>
        )}
        <div ref={chatEndRef} />
      </div>

      <div className="p-3 border-t border-white/10 bg-black/40">
        <form onSubmit={handleSend} className="relative">
          <input 
            type="text"
            value={input}
            onChange={e => handleInput(e.target.value)}
            className="w-full bg-white/5 border border-white/10 rounded-full pl-4 pr-10 py-2 text-xs text-white focus:outline-none focus:border-indigo-500"
            placeholder="Type a message..."
          />
          <button type="submit" disabled={!input.trim()} className="absolute right-1 top-1 p-1 bg-indigo-500 rounded-full text-white disabled:opacity-50 hover:bg-indigo-400">
            <Send className="w-3.5 h-3.5 ml-0.5" />
          </button>
        </form>
      </div>
    </div>
  );
};

