import React, { useState, useEffect } from 'react';
import { X, Crown, UserPlus, LogOut, Trash2, Search, Loader2, Edit2 } from 'lucide-react';
import { apiClient } from '../../../shared/api/axios';
import { useAuthStore } from '../../../app/store/useAuthStore';

interface GroupInfoDrawerProps {
  isOpen: boolean;
  onClose: () => void;
  detail: any;
  onRefresh: () => void;
}

export const GroupInfoDrawer: React.FC<GroupInfoDrawerProps> = ({ isOpen, onClose, detail, onRefresh }) => {
  const currentUser = useAuthStore(s => s.user);
  const currentUserId = currentUser?.id;
  const [showAddMember, setShowAddMember] = useState(false);
  const [memberSearch, setMemberSearch] = useState('');
  const [searchResults, setSearchResults] = useState<any[]>([]);
  const [searching, setSearching] = useState(false);
  const [actionLoading, setActionLoading] = useState<string | null>(null);
  const [isEditing, setIsEditing] = useState(false);
  const [editForm, setEditForm] = useState({ name: detail.name, description: detail.description || '' });
  const [templates, setTemplates] = useState<any[]>([]);

  const myRole = detail?.members?.find((m: any) => m.id === currentUserId)?.role;
  const isAdmin = myRole === 'admin';

  const handleSearchMembers = async (query: string) => {
    setMemberSearch(query);
    if (!query.trim()) { setSearchResults([]); return; }
    setSearching(true);
    try {
      const res = await apiClient.get('/friends');
      const existingIds = new Set(detail.members.map((m: any) => m.id));
      const filtered = res.data.filter((f: any) =>
        !existingIds.has(f.id) &&
        (f.display_name?.toLowerCase().includes(query.toLowerCase()) ||
         f.email?.toLowerCase().includes(query.toLowerCase()) ||
         f.phone_number?.toLowerCase().includes(query.toLowerCase()))
      );
      setSearchResults(filtered);
    } catch {
      setSearchResults([]);
    } finally {
      setSearching(false);
    }
  };

  const handleAddMember = async (userId: string) => {
    setActionLoading(userId);
    try {
      await apiClient.post(`/groups/${detail.id}/members`, { userId });
      setMemberSearch('');
      setSearchResults([]);
      setShowAddMember(false);
      onRefresh();
    } catch (err: any) {
      alert(err.response?.data?.error || 'Failed to add member');
    } finally {
      setActionLoading(null);
    }
  };

  const handleRemoveMember = async (userId: string, name: string) => {
    if (!confirm(`Remove ${name} from this group?`)) return;
    setActionLoading(userId);
    try {
      await apiClient.delete(`/groups/${detail.id}/members/${userId}`);
      onRefresh();
    } catch (err: any) {
      alert(err.response?.data?.error || 'Failed to remove member');
    } finally {
      setActionLoading(null);
    }
  };

  const handleToggleRole = async (userId: string, currentRole: string) => {
    setActionLoading(userId);
    const newRole = currentRole === 'admin' ? 'member' : 'admin';
    try {
      await apiClient.put(`/groups/${detail.id}/members/${userId}/role`, { role: newRole });
      onRefresh();
    } catch (err: any) {
      alert(err.response?.data?.error || 'Failed to change role');
    } finally {
      setActionLoading(null);
    }
  };

  const handleLeaveGroup = async () => {
    if (!confirm('Are you sure you want to leave this group?')) return;
    setActionLoading('leave');
    try {
      await apiClient.delete(`/groups/${detail.id}/members/${currentUserId}`);
      window.location.href = '/groups';
    } catch (err: any) {
      alert(err.response?.data?.error || 'Failed to leave group');
    } finally {
      setActionLoading(null);
    }
  };

  const handleUpdateGroup = async () => {
    setActionLoading('update');
    try {
      await apiClient.put(`/groups/${detail.id}`, editForm);
      setIsEditing(false);
      onRefresh();
    } catch (err: any) {
      alert(err.response?.data?.error || 'Failed to update group');
    } finally {
      setActionLoading(null);
    }
  };

  const handleArchiveGroup = async () => {
    if (!confirm(`Are you sure you want to ${detail.is_archived ? 'unarchive' : 'archive'} this group?`)) return;
    setActionLoading('archive');
    try {
      await apiClient.post(`/groups/${detail.id}/archive`, { isArchived: !detail.is_archived });
      onRefresh();
    } catch (err: any) {
      alert(err.response?.data?.error || 'Failed to update archive status');
    } finally {
      setActionLoading(null);
    }
  };

  const fetchTemplates = async () => {
    try {
      const res = await apiClient.get(`/groups/${detail.id}/templates`);
      setTemplates(res.data.filter((t: any) => t.is_active));
    } catch (err) {
      console.error(err);
    }
  };

  const handleDeleteTemplate = async (id: string) => {
    if (!confirm('Cancel this recurring expense?')) return;
    try {
      await apiClient.delete(`/groups/templates/${id}`);
      fetchTemplates();
    } catch (err) {
      console.error(err);
    }
  };

  useEffect(() => {
    if (isOpen && detail?.id) {
      fetchTemplates();
    }
  }, [isOpen, detail?.id]);

  if (!isOpen || !detail) return null;

  return (
    <div className="fixed inset-0 z-50 flex justify-end bg-black/50 backdrop-blur-sm" onClick={onClose}>
      <div 
        className="w-full max-w-sm h-full bg-zinc-900 border-l border-white/10 shadow-2xl flex flex-col overflow-hidden animate-in slide-in-from-right duration-300"
        onClick={e => e.stopPropagation()}
      >
        {/* Header */}
        <div className="p-5 border-b border-white/10 flex items-center justify-between shrink-0 bg-black/30">
          <h3 className="text-lg font-bold text-white">Group Info</h3>
          <div className="flex items-center gap-2">
            {isAdmin && !isEditing && (
              <button onClick={() => setIsEditing(true)} className="p-1.5 hover:bg-white/10 rounded-lg text-zinc-400 hover:text-white transition-colors">
                <Edit2 className="w-4 h-4" />
              </button>
            )}
            <button onClick={onClose} className="text-zinc-400 hover:text-white transition-colors">
              <X className="w-5 h-5" />
            </button>
          </div>
        </div>

        <div className="flex-1 overflow-y-auto custom-scrollbar">
          {/* Group Identity */}
          <div className="p-6 border-b border-white/5">
            {isEditing ? (
              <div className="space-y-4">
                <div className="w-16 h-16 rounded-2xl bg-indigo-500/20 border border-indigo-500/30 flex items-center justify-center mb-4 mx-auto">
                   <span className="text-2xl font-black text-indigo-400">{editForm.name?.charAt(0)?.toUpperCase()}</span>
                </div>
                <div>
                  <label className="block text-[10px] font-bold text-zinc-500 uppercase tracking-widest mb-1">Name</label>
                  <input 
                    type="text"
                    value={editForm.name}
                    onChange={e => setEditForm({...editForm, name: e.target.value})}
                    className="w-full bg-black/50 border border-white/10 rounded-lg px-3 py-2 text-sm text-white focus:outline-none focus:border-indigo-500"
                  />
                </div>
                <div>
                  <label className="block text-[10px] font-bold text-zinc-500 uppercase tracking-widest mb-1">Description</label>
                  <textarea 
                    value={editForm.description}
                    onChange={e => setEditForm({...editForm, description: e.target.value})}
                    rows={2}
                    className="w-full bg-black/50 border border-white/10 rounded-lg px-3 py-2 text-sm text-white focus:outline-none focus:border-indigo-500 resize-none"
                    placeholder="Short purpose of this group..."
                  />
                </div>
                <div className="flex gap-2">
                   <button 
                    onClick={() => setIsEditing(false)}
                    className="flex-1 py-2 rounded-lg text-xs font-bold text-zinc-400 hover:text-white transition-colors"
                   >
                     Cancel
                   </button>
                   <button 
                    onClick={handleUpdateGroup}
                    disabled={actionLoading === 'update'}
                    className="flex-1 py-2 rounded-lg text-xs font-bold bg-indigo-500 text-white hover:bg-indigo-400 transition-colors"
                   >
                     Save
                   </button>
                </div>
              </div>
            ) : (
              <>
                <div className="w-16 h-16 rounded-2xl bg-indigo-500/20 border border-indigo-500/30 flex items-center justify-center mb-4 mx-auto relative group/avatar">
                  <span className="text-2xl font-black text-indigo-400">{detail.name?.charAt(0)?.toUpperCase()}</span>
                  {detail.is_archived && (
                    <div className="absolute -top-1 -right-1 bg-amber-500 text-black p-1 rounded-full border-2 border-zinc-900" title="Archived">
                      <Trash2 className="w-2.5 h-2.5" />
                    </div>
                  )}
                </div>
                <h2 className="text-xl font-bold text-white text-center mb-1">{detail.name}</h2>
                <p className="text-xs text-zinc-500 text-center font-medium uppercase tracking-widest">{detail.type}</p>
                {detail.description && (
                  <p className="text-[13px] text-zinc-400 text-center mt-3 leading-relaxed">{detail.description}</p>
                )}
                <p className="text-[10px] text-zinc-600 text-center mt-4">
                  Created {new Date(detail.created_at).toLocaleDateString('en-US', { year: 'numeric', month: 'long', day: 'numeric' })}
                </p>
              </>
            )}
          </div>

          {/* Members */}
          <div className="p-5">
            <div className="flex items-center justify-between mb-4">
              <h4 className="text-xs font-bold text-zinc-400 uppercase tracking-widest">
                {detail.members?.length} Members
              </h4>
              {isAdmin && (
                <button
                  onClick={() => setShowAddMember(!showAddMember)}
                  className="flex items-center gap-1.5 text-[11px] font-bold text-indigo-400 hover:text-indigo-300 transition-colors"
                >
                  <UserPlus className="w-3.5 h-3.5" /> Add
                </button>
              )}
            </div>

            {/* Add Member Search */}
            {showAddMember && (
              <div className="mb-4 animate-in slide-in-from-top-2 duration-200">
                <div className="relative mb-2">
                  <Search className="absolute left-3 top-2.5 w-3.5 h-3.5 text-zinc-500" />
                  <input
                    type="text"
                    value={memberSearch}
                    onChange={e => handleSearchMembers(e.target.value)}
                    className="w-full bg-black/50 border border-white/10 rounded-lg pl-8 pr-3 py-2 text-xs text-white focus:outline-none focus:border-indigo-500"
                    placeholder="Search friends..."
                    autoFocus
                  />
                </div>
                {searching && <div className="text-center py-2"><Loader2 className="w-4 h-4 animate-spin text-zinc-500 mx-auto" /></div>}
                {searchResults.map(f => (
                  <button
                    key={f.id}
                    onClick={() => handleAddMember(f.id)}
                    disabled={actionLoading === f.id}
                    className="w-full text-left px-3 py-2.5 flex items-center gap-3 hover:bg-white/5 rounded-lg transition-colors"
                  >
                    <div className="w-7 h-7 rounded-full bg-white/10 flex items-center justify-center text-[10px] font-bold text-white">
                      {f.display_name?.charAt(0)?.toUpperCase()}
                    </div>
                    <div className="flex-1 min-w-0">
                      <p className="text-xs font-medium text-white truncate">{f.display_name}</p>
                    </div>
                    {actionLoading === f.id ? (
                      <Loader2 className="w-3.5 h-3.5 animate-spin text-zinc-500" />
                    ) : (
                      <UserPlus className="w-3.5 h-3.5 text-indigo-400" />
                    )}
                  </button>
                ))}
              </div>
            )}

            {/* Members List */}
            <div className="flex flex-col gap-1">
              {detail.members?.map((m: any) => {
                const isSelf = m.id === currentUserId;
                const memberIsAdmin = m.role === 'admin';
                return (
                  <div key={m.id} className="flex items-center gap-3 p-3 rounded-xl hover:bg-white/[0.03] transition-colors group">
                    <div className="w-9 h-9 rounded-full bg-white/10 flex items-center justify-center text-xs font-bold text-white shrink-0">
                      {m.display_name?.charAt(0)?.toUpperCase()}
                    </div>
                    <div className="flex-1 min-w-0">
                      <div className="flex items-center gap-2">
                        <span className="text-sm font-semibold text-white truncate">
                          {m.display_name} {isSelf && <span className="text-zinc-500 font-normal">(You)</span>}
                        </span>
                        {memberIsAdmin && (
                          <span className="inline-flex items-center gap-1 px-1.5 py-0.5 rounded text-[9px] font-bold bg-amber-500/20 text-amber-400 border border-amber-500/30 shrink-0">
                            <Crown className="w-2.5 h-2.5" /> Admin
                          </span>
                        )}
                      </div>
                      <p className="text-[10px] text-zinc-600 font-medium">
                        Joined {new Date(m.joined_at).toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' })}
                      </p>
                    </div>
                    {/* Admin Actions */}
                    {isAdmin && !isSelf && (
                      <div className="flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-all">
                        <button
                          onClick={() => handleToggleRole(m.id, m.role)}
                          disabled={actionLoading === m.id}
                          className="p-1.5 text-indigo-400/60 hover:text-indigo-400 hover:bg-indigo-500/10 rounded transition-all"
                          title={memberIsAdmin ? "Remove admin" : "Make admin"}
                        >
                          {actionLoading === m.id ? <Loader2 className="w-3.5 h-3.5 animate-spin" /> : <Crown className="w-3.5 h-3.5" />}
                        </button>
                        <button
                          onClick={() => handleRemoveMember(m.id, m.display_name)}
                          disabled={actionLoading === m.id}
                          className="p-1.5 text-rose-400/60 hover:text-rose-400 hover:bg-rose-500/10 rounded transition-all"
                          title="Remove member"
                        >
                          {actionLoading === m.id ? <Loader2 className="w-3.5 h-3.5 animate-spin" /> : <Trash2 className="w-3.5 h-3.5" />}
                        </button>
                      </div>
                    )}
                  </div>
                );
              })}
            </div>
          </div>

          {/* Recurring Expenses */}
          <div className="p-5 border-t border-white/5">
             <h4 className="text-xs font-bold text-zinc-400 uppercase tracking-widest mb-4">
                Recurring Expenses
             </h4>
             <div className="flex flex-col gap-2">
               {templates.length === 0 ? (
                 <p className="text-[11px] text-zinc-600">No active recurring expenses.</p>
               ) : (
                 templates.map(t => (
                   <div key={t.id} className="p-3 rounded-xl bg-white/[0.03] border border-white/5 flex items-center justify-between group/tmp">
                     <div className="min-w-0">
                       <p className="text-xs font-bold text-white truncate">{t.template.description}</p>
                       <p className="text-[10px] text-zinc-500">Γé╣{t.template.amount} ΓÇó {t.frequency}</p>
                     </div>
                     <button 
                       onClick={() => handleDeleteTemplate(t.id)}
                       className="opacity-0 group-hover/tmp:opacity-100 p-1.5 text-zinc-500 hover:text-rose-400 transition-all"
                       title="Cancel Recurring"
                     >
                        <X className="w-3.5 h-3.5" />
                     </button>
                   </div>
                 ))
               )}
             </div>
          </div>
        </div>

        {/* Footer: Leave/Archive Group */}
        <div className="p-4 border-t border-white/5 shrink-0 space-y-2">
          {isAdmin ? (
            <button
              onClick={handleArchiveGroup}
              disabled={actionLoading === 'archive'}
              className={`w-full flex items-center justify-center gap-2 px-4 py-3 rounded-xl border text-sm font-bold transition-colors ${detail.is_archived ? 'bg-indigo-500/10 border-indigo-500/20 text-indigo-400 hover:bg-indigo-500/20' : 'bg-amber-500/10 border-amber-500/20 text-amber-400 hover:bg-amber-500/20'}`}
            >
              <Trash2 className="w-4 h-4" />
              {detail.is_archived ? 'Unarchive Group' : 'Archive Group'}
            </button>
          ) : (
            <button
              onClick={handleLeaveGroup}
              disabled={actionLoading === 'leave'}
              className="w-full flex items-center justify-center gap-2 px-4 py-3 rounded-xl bg-rose-500/10 border border-rose-500/20 text-rose-400 text-sm font-bold hover:bg-rose-500/20 transition-colors disabled:opacity-50"
            >
              {actionLoading === 'leave' ? <Loader2 className="w-4 h-4 animate-spin" /> : <LogOut className="w-4 h-4" />}
              Leave Group
            </button>
          )}
        </div>
      </div>
    </div>
  );
};

import { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { apiClient } from '../../../shared/api/axios';
import { ArrowLeft, Crown, Receipt, Banknote, Edit2, Trash2, Bell, Loader2, Calendar } from 'lucide-react';
import { ExpenseModal } from '../../expenses/components/ExpenseModal';
import { ExpenseCharts } from '../components/ExpenseCharts';
import { GroupChat } from '../components/GroupChat';
import { GroupInfoDrawer } from '../components/GroupInfoDrawer';
import { GroupCalendarTimeline } from '../components/GroupCalendarTimeline';
import { InviteModal } from '../../../shared/components/InviteModal';
import { InviteModal } from '../../../shared/components/InviteModal';
import { getFirstName, getSplitSummary } from '../../../shared/utils/expenseUtils';
import { Trophy } from 'lucide-react';

export const GroupDetail = () => {
  const { id } = useParams();
  const navigate = useNavigate();
  const [detail, setDetail] = useState<any>(null);
  const [expenses, setExpenses] = useState<any[]>([]);
  const [leaderboard, setLeaderboard] = useState<any[]>([]);
  const [balances, setBalances] = useState<any[]>([]);
  const [isExpenseModalOpen, setExpenseModalOpen] = useState(false);
  const [expenseToEdit, setExpenseToEdit] = useState<any>(null);
  const [loadingReminders, setLoadingReminders] = useState<Record<string, boolean>>({});
  const [isInfoOpen, setInfoOpen] = useState(false);
  const [isInviteOpen, setInviteOpen] = useState(false);
  const [isTimelineVisible, setIsTimelineVisible] = useState(false);
  const [timelineFilterDate, setTimelineFilterDate] = useState<string | null>(null);

  const totalOwedToMe = balances.filter((b: any) => b.amount > 0).reduce((sum: number, b: any) => sum + parseFloat(b.amount), 0);
  const totalIOwe = Math.abs(balances.filter((b: any) => b.amount < 0).reduce((sum: number, b: any) => sum + parseFloat(b.amount), 0));

  const refreshData = () => {
    if (!id) return;
    Promise.all([
      apiClient.get(`/groups/${id}`),
      apiClient.get(`/groups/${id}/expenses`),
      apiClient.get(`/groups/${id}/leaderboard`),
      apiClient.get(`/groups/${id}/balances`)
    ]).then(([d, e, l, b]) => {
      setDetail(d.data);
      setExpenses(e.data);
      setLeaderboard(l.data);
      setBalances(b.data);
    }).catch(console.error);
  };

  useEffect(() => {
    if (id) {
      Promise.all([
        apiClient.get(`/groups/${id}`),
        apiClient.get(`/groups/${id}/expenses`),
        apiClient.get(`/groups/${id}/leaderboard`),
        apiClient.get(`/groups/${id}/balances`)
      ]).then(([d, e, l, b]) => {
        setDetail(d.data);
        setExpenses(e.data);
        setLeaderboard(l.data);
        setBalances(b.data);
      }).catch(console.error);
    }
  }, [id]);

  const handleDeleteExpense = async (expenseId: string) => {
    if (!confirm('Are you sure you want to delete this expense?')) return;
    try {
      await apiClient.delete(`/expenses/${expenseId}`);
      refreshData();
    } catch (err) {
      console.error('Delete failed', err);
    }
  };

  const handleBulkSettle = async () => {
    if (!confirm('Are you sure you want to settle all outstanding debts in this group? This action cannot be undone.')) return;
    try {
      await apiClient.post(`/groups/${id}/settle-all`);
      refreshData();
    } catch (err) {
      console.error('Settle all failed', err);
    }
  };

  const handleSettleSpecificExpense = async (expenseId: string) => {
    try {
      await apiClient.post(`/expenses/${expenseId}/settle`);
      refreshData();
    } catch (err) {
      console.error('Settle specific expense failed', err);
    }
  };

  const handleRemindExpense = async (expenseId: string) => {
    setLoadingReminders(prev => ({ ...prev, [expenseId]: true }));
    try {
      await apiClient.post(`/expenses/${expenseId}/remind`);
      alert('Reminders sent to group members!');
    } catch (err) {
      console.error('Reminder failed', err);
    } finally {
      setLoadingReminders(prev => ({ ...prev, [expenseId]: false }));
    }
  };

  if (!detail) return <div className="p-8 text-white">Loading...</div>;

  return (
    <div className="flex flex-col h-full overflow-hidden relative">
      <div className="absolute top-[-200px] left-[-200px] w-[600px] h-[600px] bg-indigo-500/10 rounded-full blur-[120px] pointer-events-none" />

      {/* HEADER */}
      <div className="p-6 border-b border-white/10 flex items-center justify-between z-10 sticky top-0 bg-black/50 backdrop-blur-xl">
         <div className="flex items-center gap-4">
           <button onClick={() => navigate('/groups')} className="text-zinc-400 hover:text-white transition-colors">
             <ArrowLeft className="w-5 h-5" />
           </button>
            <div className="flex flex-col cursor-pointer" onClick={() => setInfoOpen(true)}>
              <h2 className="text-xl font-bold text-white hover:text-indigo-300 transition-colors">{detail.name}</h2>
              <span className="text-xs text-zinc-500 font-medium tracking-wide uppercase">{detail.type} ΓÇó {detail.members?.length} members</span>
            </div>
         </div>
         <div className="flex gap-3">
           <button 
             onClick={() => setIsTimelineVisible(!isTimelineVisible)}
             className={`px-4 py-2 rounded-lg text-sm font-medium transition-colors flex items-center gap-2 border ${
               isTimelineVisible 
                 ? 'bg-white/10 border-white/20 text-white' 
                 : 'bg-transparent border-white/10 text-zinc-400 hover:text-white hover:bg-white/5'
             }`}
           >
             <Calendar className="w-4 h-4" /> Timeline
           </button>
           <button 
             onClick={() => { setExpenseToEdit(null); setExpenseModalOpen(true); }}
             className="px-4 py-2 bg-white/5 hover:bg-white/10 border border-white/10 rounded-lg text-sm text-white font-medium transition-colors flex items-center gap-2"
           >
             <Receipt className="w-4 h-4" /> Add Expense
           </button>
           <button 
             onClick={handleBulkSettle}
             disabled={balances.length === 0}
             className={`px-4 py-2 rounded-lg text-sm font-bold transition-colors flex items-center gap-2 ${
               balances.length === 0
                 ? 'bg-zinc-800 text-zinc-500 cursor-not-allowed shadow-none'
                 : 'bg-indigo-500 hover:bg-indigo-400 text-white shadow-lg shadow-indigo-500/20'
             }`}
           >
             <Banknote className="w-4 h-4" /> Settle Up
           </button>
         </div>
      </div>

      <div className="flex-1 overflow-y-auto custom-scrollbar flex z-10">
         {/* Main Content: Expenses */}
         <div className="flex-1 p-8 border-r border-white/5 flex flex-col gap-8">

           {isTimelineVisible ? (
             <div className="w-full h-full animate-in fade-in duration-300">
               <GroupCalendarTimeline 
                  expenses={expenses} 
                  onDateClick={(dateStr) => {
                    setTimelineFilterDate(dateStr);
                    setIsTimelineVisible(false);
                  }}
               />
             </div>
           ) : (
             <>
               {/* Row 1: Charts & Analytics */}
               <div className="w-full animate-in fade-in duration-300">
                 <ExpenseCharts expenses={expenses} totalOwedToMe={totalOwedToMe} totalIOwe={totalIOwe} />
               </div>

               <div className="w-full animate-in fade-in duration-300">
                 <div className="flex items-center justify-between mb-4">
                   <h3 className="text-sm font-bold text-white uppercase tracking-widest flex items-center gap-2">Group Expenses</h3>
                   {timelineFilterDate && (
                     <button 
                       onClick={() => setTimelineFilterDate(null)}
                       className="text-xs font-bold bg-white/10 hover:bg-white/20 text-white px-3 py-1 rounded-full transition-colors flex items-center gap-1.5"
                     >
                       Filtered: {new Date(timelineFilterDate).toLocaleDateString()} <Trash2 className="w-3 h-3 ml-1" />
                     </button>
                   )}
                 </div>

                 <div className="flex flex-col gap-3">
                   {expenses.length === 0 ? (
                     <p className="text-zinc-500 text-sm">No expenses logged yet. Be the first!</p>
                   ) : (
                     expenses
                      .filter(e => {
                        if (!timelineFilterDate) return true;
                        const filterD = new Date(timelineFilterDate);
                        const ed = new Date(e.created_at);
                        return filterD.getDate() === ed.getDate() && filterD.getMonth() === ed.getMonth() && filterD.getFullYear() === ed.getFullYear();
                      })
                      .map((e: any) => (
                   <div key={e.id} className={`p-4 rounded-2xl border ${e.is_settled ? 'border-emerald-500/20' : 'border-white/5'} bg-white/[0.02] hover:bg-white/[0.04] transition-colors relative overflow-hidden group`}>
                      <div className={`absolute left-0 top-0 bottom-0 w-1 transition-colors ${e.is_settled ? 'bg-emerald-500/50' : 'bg-indigo-500/0 group-hover:bg-indigo-500/50'}`} />
                      <div className="flex justify-between items-start mb-1">
                        <div className="flex flex-col gap-1 pr-2">
                          <h4 className="text-[14px] font-bold text-white truncate">{e.description}</h4>
                          {e.is_involved && (
                            <div className="flex items-center gap-1.5 mt-0.5">
                              <span className={`text-[9px] font-bold uppercase tracking-wider px-1.5 py-0.5 rounded-sm ${e.is_settled ? 'bg-emerald-500/10 text-emerald-400' : 'bg-zinc-500/10 text-zinc-400'}`}>
                                 {e.is_settled ? 'Settled Up' : 'Not Settled Up'}
                              </span>
                            </div>
                          )}
                        </div>
                        <div className="flex items-center gap-1.5 shrink-0">
                          <div className="flex gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                            {!e.is_settled && e.is_involved && (
                               <button 
                                 onClick={() => handleSettleSpecificExpense(e.id)}
                                 className="px-2 py-1 bg-emerald-500/20 text-emerald-400 text-[10px] font-bold rounded hover:bg-emerald-500/40 tracking-wide uppercase" 
                                 title="Settle this specific activity"
                               >
                                 Settle Up
                               </button>
                            )}
                            <button 
                              onClick={() => handleRemindExpense(e.id)}
                              className="p-1 bg-indigo-500/20 text-indigo-400 rounded hover:bg-indigo-500/40" 
                              title="Send Reminder"
                            >
                              {loadingReminders[e.id] ? <Loader2 className="w-3.5 h-3.5 animate-spin" /> : <Bell className="w-3.5 h-3.5" />}
                            </button>
                            <button 
                              onClick={() => { setExpenseToEdit(e); setExpenseModalOpen(true); }}
                              className="p-1 bg-white/10 text-zinc-300 rounded hover:bg-white/20" 
                              title="Edit"
                            >
                              <Edit2 className="w-3.5 h-3.5" />
                            </button>
                            <button 
                              onClick={() => handleDeleteExpense(e.id)}
                              className="p-1 bg-rose-500/20 text-rose-400 rounded hover:bg-rose-500/40" 
                              title="Delete"
                            >
                              <Trash2 className="w-3.5 h-3.5" />
                            </button>
                          </div>
                          <span className="text-[14px] font-black text-white bg-white/10 px-2.5 py-0.5 rounded-full">Γé╣{e.amount}</span>
                        </div>
                      </div>
                      <div className="flex justify-between items-center text-[11px] text-zinc-500 mt-2 font-medium">
                        <span>Paid by <span className="text-indigo-400/90 font-bold">{getFirstName(e.paid_by_name)}</span> <span className="mx-1 opacity-30">ΓÇó</span>{getSplitSummary(e.participants, detail.members?.length)}</span>
                        <span>{new Date(e.created_at).toLocaleDateString('en-IN', { day: 'numeric', month: 'short', year: '2-digit' })}</span>
                      </div>
                   </div>
                 ))
               )}
             </div>
           </div>
             </>
           )}
         </div>

         {/* Right Sidebar: Leaderboard & Balances */}
         <div className="w-[350px] bg-black/20 p-8 flex flex-col gap-8">

           {/* Leaderboard (Recent Contributors) */}
           <div>
             <h3 className="text-sm font-bold text-white uppercase tracking-widest mb-4 flex items-center gap-2">
               <Trophy className="w-4 h-4 text-emerald-500" /> Top Contributors
             </h3>
             <div className="flex flex-col gap-3">
               {leaderboard.length === 0 ? (
                  <p className="text-xs text-zinc-500">No recent contributions.</p>
               ) : (
                 leaderboard.map((l, idx) => (
                   <div key={l.id} className="flex items-center justify-between p-3 rounded-xl bg-white/5 border border-white/5">
                     <div className="flex items-center gap-3">
                       <span className={`text-sm font-black w-4 ${idx === 0 ? 'text-emerald-500' : 'text-zinc-500'}`}>{idx + 1}</span>
                       <div className="w-8 h-8 flex items-center justify-center rounded-full bg-white/10 text-xs font-bold text-white">
                         {l.display_name.charAt(0)}
                       </div>
                       <span className="text-sm font-semibold text-white">{l.display_name}</span>
                     </div>
                     <span className="text-sm text-zinc-400 font-bold">Γé╣{l.total_paid}</span>
                   </div>
                 ))
               )}
             </div>
           </div>

           {/* Balances */}
            <div>
              <h3 className="text-sm font-bold text-white uppercase tracking-widest mb-1">Balances</h3>
              <p className="text-[11px] text-zinc-500 mb-4">Track who owes whom and settle up</p>
              <div className="flex flex-col gap-2">
                {balances.length === 0 ? (
                  null
                ) : (
                 balances.map((b, i) => (
                   <div key={i} className="text-[13px] p-3 rounded-lg border border-white/5 text-zinc-300 font-medium">
                     <span className="text-white font-bold">{b.owes_name}</span> owes <span className="text-white font-bold">{b.paid_by_name}</span> <span className="text-emerald-400 font-bold">Γé╣{b.amount}</span>
                   </div>
                 ))
               )}
             </div>
           </div>

         </div>
      </div>

       <ExpenseModal 
          isOpen={isExpenseModalOpen}
          onClose={() => setExpenseModalOpen(false)}
          groupId={id!}
          groupType={detail.type}
          expenseToEdit={expenseToEdit}
          onSuccess={refreshData}
          groupMembers={detail.members}
           defaultDueDay={detail.default_due_day}
       />

       <GroupChat groupId={id!} />

       <GroupInfoDrawer
         isOpen={isInfoOpen}
         onClose={() => setInfoOpen(false)}
         detail={detail}
         onRefresh={refreshData}
       />

       <InviteModal 
         isOpen={isInviteOpen}
         onClose={() => setInviteOpen(false)}
         targetId={id!}
         type="group"
         title={detail.name}
       />


    </div>
  );
};

